class Solution:
    def maxLength(self, arr) -> int:
        res = [0]
        def bt(idx, cur_mask, cur_len):
            res[0] = max(res[0], cur_len)
            for i in range(idx, len(arr)):
                s = arr[i]
                mask = 0
                dup = False
                for c in s:
                    b = 1 << (ord(c) - ord('a'))
                    if mask & b:
                        dup = True
                        break
                    mask |= b
                if not dup and (cur_mask & mask) == 0:
                    bt(i + 1, cur_mask | mask, cur_len + len(s))
        bt(0, 0, 0)
        return res[0]

