class Solution:
    def maxLength(self, arr) -> int:
        dp = [0]
        for s in arr:
            mask = 0
            dup = False
            for c in s:
                b = 1 << (ord(c) - 97)
                if mask & b:
                    dup = True
                    break
                mask |= b
            if dup:
                continue
            new_dp = []
            for prev in dp:
                if (prev & mask) == 0:
                    new_dp.append(prev | mask)
            dp.extend(new_dp)
        return max(bin(m).count('1') for m in dp)

