var maxLength = function(arr) {
    let dp = [0];
    for (const s of arr) {
        let mask = 0, dup = false;
        for (const c of s) {
            const b = 1 << (c.charCodeAt(0) - 97);
            if (mask & b) { dup = true; break; }
            mask |= b;
        }
        if (dup) continue;
        const newDp = [];
        for (const prev of dp) {
            if ((prev & mask) === 0) newDp.push(prev | mask);
        }
        dp.push(...newDp);
    }
    return Math.max(...dp.map(m => m.toString(2).split('').filter(x => x === '1').length));
};
